import React, {useRef, useState, useEffect} from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import SingleOrderSection from '../components/SingleOrderSection'
import {getUserShoppingCart, getUserProfile} from '../WebAPI.js'


const ShoppingCartWrapper = styled.div `
display:flex;
width:80%;
margin:60px auto;
justify-content:space-between;
align-items:flex-start;
`

const ItemsPart = styled.div `
width:700px;
`

const InfoPart = styled.form `
width:300px;
display:flex;
justify-content:center;
flex-direction:column;
align-items:flex-start;
`

const ItemsWrapper = styled.div `
display:flex;
flex-direction:column;
width:100%;
`


const OrderTotalInfo = styled.div `
height:60px;
width:100%;
padding:30px 0;
padding-left:100px;
box-sizing:border-box;
`

const OrderDetail =styled.div `
display:flex;
justify-content:space-between;
`

const Detail = styled.div `
font-size:0.7rem;
`

const OrderTotalDetail = styled(OrderDetail) `
font-weight:900;
`

const ShippingAdressWrapper = styled.div `
display:flex;
flex-direction:column;
width:100%;
`

const Title = styled.div `
font-size:0.9rem;
font-weight:900;
margin:20px 0;
`

const Adress = styled.div `
font-size:0.9rem;
`

const PaymentMethodCheckboxWrapper = styled.div ``

const CheckboxWrapper = styled.div `
display:flex;
align-items:center;
margin:4px 0;
font-size:0.9rem;
`

const Check = styled.input `
text-align:center;
`

const SectionTitle = styled.div `
font-size:0.7rem;
letter-spacing:2px;
color:rgba(0,0,0,0.7);
width:100%;
margin:15px 0;
`

const CardInfoInput = styled.input `
width:100%;
height:30px;
border:1px solid rgb(210, 210, 210);
box-sizing:border-box;
padding:0 10px;
color:rgb(230, 230, 230);
`

const SecurityCodeInput = styled(CardInfoInput) `
width:90%;
`

const MoreDetail = styled.div `
width:100%;
`

const CreditCardWrapper = styled.div `
display:flex;
`

const SubmitButton = styled.div `
width:140px;
height:40px;
background-color:#1C1C1C;
color:white;
border-radius:5px;
line-height:40px;
text-align:center;
margin-top:40px;
border:0;
font-size:0.9rem;
&:hover {
	background-color:white;
	color:#1C1C1C;
	border:1.5px solid #1C1C1C;
	cursor:pointer;
}
`

const NoListing = styled.div `
width:100%;
height:120%;
position:absolute;
background-color:white;
z-index:3;
display:flex;
justify-content:center;
align-items:center;
`

export default function ShoppingCart () {
	const [userShoppingCart, setUserShoppingCart] = useState([{}])
	const [userProfile, setUserProfile]= useState({})
	const [isProductInShoppingCart, setIsProductInShoppingCart] = useState(false)

	useEffect(() => {
		getUserShoppingCart(localStorage.getItem('userId'), setUserShoppingCart)
		getUserProfile(localStorage.getItem('userId'), setUserProfile)

		if (userShoppingCart.id) {
			setIsProductInShoppingCart(true)
		}

	}, [])

	let total = 0
	for (let listing of userShoppingCart) {
		total += listing.price
	}

	return (
		<>
			<Header />
			<Navbar />
			{console.log(isProductInShoppingCart)}
			{isProductInShoppingCart ? null : <NoListing>No Listing In your shopping Cart</NoListing>}
			<ShoppingCartWrapper>
				<ItemsPart>
					{console.log(total)}
					<ItemsWrapper>
						{userShoppingCart.map(listing => <SingleOrderSection key={listing.id} listing={listing} setter={setUserShoppingCart}/>)}
						<OrderTotalInfo>
							<OrderDetail>
								<Detail>Total</Detail>
								<Detail>{isNaN(total) ? null : total}</Detail>
							</OrderDetail>
							<OrderDetail>
								<Detail>Duties & Taxes</Detail>
								<Detail>300</Detail>
							</OrderDetail>
							<OrderTotalDetail>
								<Detail>Order Total</Detail>
								<Detail>{isNaN(total) ? null : total+300}</Detail>
							</OrderTotalDetail>
						</OrderTotalInfo>
					</ItemsWrapper>
				</ItemsPart>
				<InfoPart>
					<ShippingAdressWrapper>
						<Title>Shipping Adress</Title>
						<Adress>{userProfile.shippingName}</Adress>
						<Adress>{userProfile.address}</Adress>
						<Adress>{userProfile.city}</Adress>
						<Adress>{userProfile.nation}</Adress>
					</ShippingAdressWrapper>
					<ShippingAdressWrapper>
						<Title>Payment Method</Title>
						<PaymentMethodCheckboxWrapper>
							<label><CheckboxWrapper><Check type='checkbox' />Credit Card</CheckboxWrapper></label>
							<label><CheckboxWrapper><Check type='checkbox' />Apple Pay</CheckboxWrapper></label>
							<label><CheckboxWrapper><Check type='checkbox' />Paypal</CheckboxWrapper></label>
						</PaymentMethodCheckboxWrapper>
					</ShippingAdressWrapper>
					<ShippingAdressWrapper>
						<Title>Credit Card Details</Title>
							<MoreDetail>
								<SectionTitle>Card Number</SectionTitle>
								<CardInfoInput placeholder='1234 1234 1234 1234'/>
							</MoreDetail>
							<MoreDetail>
								<SectionTitle>Card Holder's Name</SectionTitle>
								<CardInfoInput/>
							</MoreDetail>
							<CreditCardWrapper>
								<MoreDetail>
									<SectionTitle>Expiration Date</SectionTitle>
									<SecurityCodeInput placeholder='MM/YY'/>
								</MoreDetail>
								<MoreDetail>
									<SectionTitle>Security Code</SectionTitle>
									<SecurityCodeInput placeholder='CVC'/>
								</MoreDetail>
							</CreditCardWrapper>
					</ShippingAdressWrapper>
					<SubmitButton>Place the Order</SubmitButton>
				</InfoPart>
			</ShoppingCartWrapper>
		</>	
	)
}
